+  inner.floatLE(opts.expirationTime ?? 1.0);
+  inner.uint32LE(0);
+  inner.cString(opts.subject);
+  inner.cString(opts.body);
+  inner.uint8(opts.itemCount ?? 0);
+  const entryBytes = inner.finish();
+  w.uint16LE(entryBytes.byteLength);
