 501→+function formatMailAge(days: number): string {
 502→+  if (days < 1 / 24) return "< 1m";
 503→+  if (days < 1) {
 504→+    const hours = Math.floor(days * 24);
 505→+    return `${hours}h`;
 506→+  }
