 511→+function senderLabel(entry: MailEntry): string {
 512→+  if (entry.messageType === MailMessageType.AUCTION) return "Auction House";
 513→+  if (entry.messageType === MailMessageType.CREATURE) return "NPC";
 514→+  if (entry.messageType === MailMessageType.GAMEOBJECT) return "System";
 515→+  if (entry.messageType === MailMessageType.CALENDAR) return "Calendar";
 516→+  return "";
 517→+}
