 519→+export function formatMailList(
 520→+  entries: MailEntry[],
 521→+  nameCache: Map<number, string>,
 522→+): string {
 523→+  if (entries.length === 0) return "[mail] Mailbox is empty";
 524→+  const lines: string[] = [`=== Mailbox (${entries.length} messages) ===`];
 525→+  for (let i = 0; i < entries.length; i++) {
 526→+    const e = entries[i]!;
 527→+    const unread = !(e.flags & MailCheckMask.READ);
 528→+    const marker = unread ? "*" : " ";
 529→+    const idx = `#${i + 1}`;
 530→+    let sender = senderLabel(e);
 531→+    if (!sender && e.senderGuid !== undefined) {
 532→+      const guidLow = Number(e.senderGuid & 0xffffffffn);
 533→+      sender = nameCache.get(guidLow) ?? `Player`;
 534→+    }
 535→+    const subj =
 536→+      e.subject.length > 30 ? e.subject.slice(0, 27) + "..." : e.subject;
 537→+    const age = formatMailAge(e.expirationDays);
 538→+    lines.push(
 539→+      `${marker}${idx.padEnd(4)} ${sender.padEnd(15)} ${subj.padEnd(32)} ${age}`,
 540→+    );
 541→+  }
 542→+  return lines.join("\n");
 543→+}
