 550→+      index: i + 1,
 551→+      messageId: e.messageId,
 552→+      messageType: e.messageType,
 553→+      subject: e.subject,
 554→+      read: !!(e.flags & MailCheckMask.READ),
 555→+      expirationDays: e.expirationDays,
 556→+      money: e.money,
 557→+      itemCount: e.itemCount,
 558→+    })),
 559→+  });
 560→+}
