 562→+export function formatMailRead(entry: MailEntry, sender: string): string {
 563→+  const age = formatMailAge(entry.expirationDays);
 564→+  const lines = [
 565→+    `From: ${sender}`,
 566→+    `Subject: ${entry.subject}`,
 567→+    `Date: ${age} ago`,
 568→+  ];
 569→+  if (entry.money > 0) {
 570→+    const gold = Math.floor(entry.money / 10000);
 571→+    const silver = Math.floor((entry.money % 10000) / 100);
 572→+    const copper = entry.money % 100;
 573→+    const parts: string[] = [];
 574→+    if (gold > 0) parts.push(`${gold}g`);
 575→+    if (silver > 0) parts.push(`${silver}s`);
 576→+    if (copper > 0) parts.push(`${copper}c`);
 577→+    lines.push(`Money: ${parts.join(" ")}`);
 578→+  }
 579→+  if (entry.itemCount > 0) {
 580→+    lines.push(`Attachments: ${entry.itemCount} item(s)`);
 581→+  }
 582→+  lines.push("");
 583→+  lines.push(entry.body || "(no message)");
 584→+  return lines.join("\n");
 585→+}
