 943→+function writeMailEntry(
 944→+  w: PacketWriter,
 945→+  opts: {
 946→+    messageId: number;
 947→+    messageType?: number;
 948→+    senderGuid?: bigint;
 949→+    senderEntry?: number;
 950→+    subject: string;
 951→+    body: string;
 952→+    flags?: number;
 953→+    expirationTime?: number;
 954→+    money?: number;
 955→+    itemCount?: number;
 956→+  },
 957→+): void {
 958→+  const msgType = opts.messageType ?? MailMessageType.NORMAL;
 959→+  const inner = new PacketWriter();
 960→+  inner.uint32LE(opts.messageId);
 961→+  inner.uint8(msgType);
 962→+  if (msgType === MailMessageType.NORMAL) {
 963→+    inner.uint64LE(opts.senderGuid ?? 0n);
 964→+  } else {
 965→+    inner.uint32LE(opts.senderEntry ?? 0);
 966→+  }
 967→+  inner.uint32LE(0);
 968→+  inner.uint32LE(0);
 969→+  inner.uint32LE(41);
 970→+  inner.uint32LE(opts.money ?? 0);
 971→+  inner.uint32LE(opts.flags ?? MailCheckMask.HAS_BODY);
 972→+  inner.floatLE(opts.expirationTime ?? 1.0);
 973→+  inner.uint32LE(0);
 974→+  inner.cString(opts.subject);
 975→+  inner.cString(opts.body);
 976→+  inner.uint8(opts.itemCount ?? 0);
 977→+  const entryBytes = inner.finish();
 978→+  w.uint16LE(entryBytes.byteLength);
 979→+  w.rawBytes(entryBytes);
 980→+}
