 18→describe("parseShowMailbox", () => {
 19→  test("reads mailbox guid", () => {
 20→    const w = new PacketWriter();
 21→    w.uint64LE(0x1234n);
 22→    const result = parseShowMailbox(new PacketReader(w.finish()));
 23→    expect(result).toBe(0x1234n);
 24→  });
 25→
 26→  test("consumes all bytes", () => {
 27→    const w = new PacketWriter();
 28→    w.uint64LE(99n);
 29→    const r = new PacketReader(w.finish());
 30→    parseShowMailbox(r);
 31→    expect(r.remaining).toBe(0);
 32→  });
 33→});
