 54→    expect(r.uint8()).toBe(0);
 55→    expect(r.uint32LE()).toBe(0);
 56→    expect(r.uint32LE()).toBe(0);
 57→    expect(r.uint32LE()).toBe(0);
 58→    expect(r.uint32LE()).toBe(0);
