453→export function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
454→  const entries = parseUpdateObject(r);
455→  for (const entry of entries) {
456→    switch (entry.type) {
457→      case "create": {
458→        const { _changed: _co, ...objFields } = extractObjectFields(
459→          entry.fields,
460→        );
461→        let extraFields: Record<string, unknown> = {};
462→        if (
463→          entry.objectType === ObjectType.UNIT ||
464→          entry.objectType === ObjectType.PLAYER
465→        ) {
466→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
467→          extraFields = rest;
468→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
469→          const { _changed: _cg, ...rest } = extractGameObjectFields(
470→            entry.fields,
471→          );
472→          extraFields = rest;
473→        }
474→        const cachedName = lookupCachedName(
475→          conn,
476→          entry.guid,
477→          entry.objectType,
478→          objFields.entry,
479→        );
480→        conn.entityStore.create(entry.guid, entry.objectType, {
481→          ...objFields,
482→          ...extraFields,
483→          ...(cachedName ? { name: cachedName } : {}),
484→          ...(entry.position ? { position: entry.position } : {}),
485→          rawFields: new Map(entry.fields),
486→        } as any);
487→        if (!cachedName) {
488→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
489→        }
490→        break;
491→      }
492→      case "values": {
493→        const entity = conn.entityStore.get(entry.guid);
494→        if (!entity) break;
495→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
496→        let extraFields: Record<string, unknown> = {};
497→        if (
498→          entity.objectType === ObjectType.UNIT ||
499→          entity.objectType === ObjectType.PLAYER
500→        ) {
501→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
502→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
503→          extraFields = extractGameObjectFields(entry.fields);
504→        }
505→        const allChanged = [
506→          ...(objFields._changed || []),
507→          ...((extraFields as any)._changed || []),
508→        ];
509→        const merged: Record<string, unknown> = {};
510→        for (const key of allChanged) {
511→          if (key in extraFields) merged[key] = (extraFields as any)[key];
512→          else if (key in objFields) merged[key] = (objFields as any)[key];
513→        }
514→        conn.entityStore.update(entry.guid, merged);
515→        for (const [k, v] of entry.fields) {
516→          const existing = conn.entityStore.get(entry.guid);
517→          if (existing) existing.rawFields.set(k, v);
518→        }
519→        break;
520→      }
521→      case "movement": {
522→        conn.entityStore.setPosition(entry.guid, entry.position);
523→        break;
524→      }
525→      case "outOfRange": {
526→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
527→        break;
528→      }
529→      case "nearObjects": {
530→        break;
531→      }
532→    }
533→  }
534→}
