536→export function handleCompressedUpdateObject(
537→  conn: WorldConn,
538→  r: PacketReader,
539→): void {
540→  const uncompressedSize = r.uint32LE();
541→  const compressed = r.bytes(r.remaining);
542→  const decompressed = inflateSync(compressed);
543→  if (decompressed.length !== uncompressedSize) {
544→    throw new Error(
545→      `Compressed update size mismatch: expected ${uncompressedSize}, got ${decompressed.length}`,
546→    );
547→  }
548→  handleUpdateObject(conn, new PacketReader(new Uint8Array(decompressed)));
549→}
