574→export function queryEntityName(
575→  conn: WorldConn,
576→  guid: bigint,
577→  objectType: number,
578→  entry: number | undefined,
579→): void {
580→  if (objectType === ObjectType.PLAYER) {
581→    const guidLow = Number(guid & 0xffffffffn);
582→    const key = `player:${guidLow}`;
583→    if (conn.pendingNameQueries.has(key)) return;
584→    conn.pendingNameQueries.add(key);
585→    const w = new PacketWriter();
586→    w.uint64LE(guid);
587→    sendPacket(conn, GameOpcode.CMSG_NAME_QUERY, w.finish());
588→    return;
589→  }
590→  if (entry === undefined) return;
591→  const key = `${objectType}:${entry}`;
592→  if (conn.pendingNameQueries.has(key)) return;
593→  conn.pendingNameQueries.add(key);
594→  if (objectType === ObjectType.UNIT) {
595→    sendPacket(
596→      conn,
597→      GameOpcode.CMSG_CREATURE_QUERY,
598→      buildCreatureQuery(entry, guid),
599→    );
600→    return;
601→  }
602→  if (objectType === ObjectType.GAMEOBJECT) {
603→    sendPacket(
604→      conn,
605→      GameOpcode.CMSG_GAMEOBJECT_QUERY,
606→      buildGameObjectQuery(entry, guid),
607→    );
608→    return;
609→  }
