642→      }
643→    }
644→  }
645→}
646→
647→export function handlePartyMemberStatsMsg(
648→  conn: WorldConn,
649→  r: PacketReader,
650→  isFull = false,
651→): void {
652→  const stats = parsePartyMemberStats(r, isFull);
653→  conn.onGroupEvent?.({
654→    type: "member_stats",
655→    guidLow: stats.guidLow,
656→    online: stats.online,
657→    hp: stats.hp,
658→    maxHp: stats.maxHp,
659→    level: stats.level,
660→  });
661→}
