663→export function handleContactList(conn: WorldConn, r: PacketReader): void {
664→  const list = parseContactList(r);
665→  const friends: FriendEntry[] = [];
666→  for (const contact of list.contacts) {
667→    if (!(contact.flags & SocialFlag.FRIEND)) continue;
668→    const guidLow = Number(contact.guid & 0xffffffffn);
669→    const name = conn.nameCache.get(guidLow) ?? "";
670→    friends.push({
671→      guid: contact.guid,
672→      name,
673→      note: contact.note,
674→      status: contact.status ?? 0,
675→      area: contact.area ?? 0,
676→      level: contact.level ?? 0,
677→      playerClass: contact.playerClass ?? 0,
678→    });
679→    if (!name) ensureNameQuery(conn, contact.guid);
680→  }
681→  conn.friendStore.set(friends);
682→
683→  const ignored: IgnoreEntry[] = [];
684→  for (const contact of list.contacts) {
685→    if (!(contact.flags & SocialFlag.IGNORED)) continue;
686→    const guidLow = Number(contact.guid & 0xffffffffn);
687→    const name = conn.nameCache.get(guidLow) ?? "";
688→    ignored.push({ guid: contact.guid, name });
689→    if (!name) ensureNameQuery(conn, contact.guid);
690→  }
691→  conn.ignoreStore.set(ignored);
692→}
