694→export function handleFriendStatus(conn: WorldConn, r: PacketReader): void {
695→  const packet = parseFriendStatus(r);
696→  const guidLow = Number(packet.guid & 0xffffffffn);
697→
698→  switch (packet.result) {
699→    case FriendResult.ADDED_ONLINE:
700→    case FriendResult.ADDED_OFFLINE: {
701→      const name = conn.nameCache.get(guidLow) ?? "";
702→      conn.friendStore.add({
703→        guid: packet.guid,
704→        name,
705→        note: packet.note ?? "",
706→        status: packet.status ?? 0,
707→        area: packet.area ?? 0,
708→        level: packet.level ?? 0,
709→        playerClass: packet.playerClass ?? 0,
710→      });
711→      if (!name) ensureNameQuery(conn, packet.guid);
712→      break;
713→    }
714→    case FriendResult.ONLINE:
715→      conn.friendStore.update(packet.guid, {
716→        status: packet.status ?? FriendStatus.ONLINE,
717→        area: packet.area ?? 0,
718→        level: packet.level ?? 0,
719→        playerClass: packet.playerClass ?? 0,
720→      });
721→      break;
722→    case FriendResult.OFFLINE:
723→      conn.friendStore.update(packet.guid, { status: FriendStatus.OFFLINE });
724→      break;
725→    case FriendResult.REMOVED:
726→      conn.friendStore.remove(packet.guid);
727→      break;
728→    case FriendResult.IGNORE_ADDED: {
729→      const name = conn.nameCache.get(guidLow) ?? "";
730→      conn.ignoreStore.add({ guid: packet.guid, name });
731→      if (!name) ensureNameQuery(conn, packet.guid);
732→      break;
733→    }
734→    case FriendResult.IGNORE_REMOVED:
735→      conn.ignoreStore.remove(packet.guid);
736→      break;
737→    case FriendResult.IGNORE_FULL:
738→    case FriendResult.IGNORE_SELF:
739→    case FriendResult.IGNORE_NOT_FOUND:
740→    case FriendResult.IGNORE_ALREADY:
741→    case FriendResult.IGNORE_AMBIGUOUS: {
742→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
743→      conn.onIgnoreEvent?.({
744→        type: "ignore-error",
745→        result: packet.result,
746→        name,
747→      });
748→      break;
749→    }
750→    default: {
751→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
752→      conn.onFriendEvent?.({
753→        type: "friend-error",
754→        result: packet.result,
755→        name,
756→      });
757→      break;
758→    }
759→  }
760→}
