 300→function drainWorldPackets(conn: WorldConn): void {
 301→  while (true) {
 302→    if (!conn.pendingHeader) {
 303→      if (conn.buf.length < INCOMING_HEADER_SIZE) break;
 304→      conn.pendingHeader = decryptIncomingHeader(
 305→        conn.buf.drain(INCOMING_HEADER_SIZE),
 306→        conn.arc4,
 307→      );
 308→    }
 309→    const bodySize = conn.pendingHeader.size - 2;
 310→    if (conn.buf.length < bodySize) break;
 311→
 312→    const { opcode } = conn.pendingHeader;
 313→    conn.pendingHeader = undefined;
 314→    try {
 315→      conn.dispatch.handle(opcode, new PacketReader(conn.buf.drain(bodySize)));
 316→    } catch (err) {
 317→      if (err instanceof Error) {
 318→        conn.onPacketError?.(opcode, err);
 319→      }
 320→    }
 321→  }
 322→}
