 324→async function authenticateWorld(
 325→  conn: WorldConn,
 326→  config: ClientConfig,
 327→  auth: AuthResult,
 328→): Promise<void> {
 329→  const challenge = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_CHALLENGE);
 330→  challenge.uint32LE();
 331→  const serverSeed = challenge.bytes(4);
 332→
 333→  const body = await buildWorldAuthPacket(
 334→    config.account,
 335→    auth.sessionKey,
 336→    serverSeed,
 337→    auth.realmId,
 338→    config.clientSeed,
 339→  );
 340→  conn.socket.write(buildOutgoingPacket(GameOpcode.CMSG_AUTH_SESSION, body));
 341→  conn.arc4 = new Arc4(auth.sessionKey);
 342→
 343→  const resp = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_RESPONSE);
 344→  const status = resp.uint8();
 345→  if (status !== 0x0c) {
 346→    const names: Record<number, string> = {
 347→      0x0d: "system error",
 348→      0x15: "account in use",
 349→    };
 350→    const label = names[status] ?? `status 0x${status.toString(16)}`;
 351→    throw new Error(`World auth failed: ${label}`);
 352→  }
 353→}
