 365→  );
 366→  if (!char) {
 367→    throw new Error(
 368→      `Character "${config.character}" not found. Available: ${chars.map((c) => c.name).join(", ")}`,
 369→    );
 370→  }
 371→
 372→  conn.selfName = char.name;
 373→  conn.selfGuidLow = char.guidLow;
 374→  conn.selfGuidHigh = char.guidHigh;
 375→  conn.guildId = char.guildId;
 376→
