 385→function startPingLoop(
 386→  conn: WorldConn,
 387→  intervalMs: number,
 388→): ReturnType<typeof setInterval> {
 389→  return setInterval(() => {
 390→    const w = new PacketWriter();
 391→    w.uint32LE(0);
 392→    w.uint32LE(0);
