 18→const CHAT_TYPE_LABELS: Record<number, string> = {
 19→  [ChatType.SYSTEM]: "system",
 20→  [ChatType.SAY]: "say",
 21→  [ChatType.PARTY]: "party",
 22→  [ChatType.RAID]: "raid",
 23→  [ChatType.GUILD]: "guild",
 24→  [ChatType.OFFICER]: "officer",
 25→  [ChatType.YELL]: "yell",
 26→  [ChatType.WHISPER]: "whisper from",
 27→  [ChatType.WHISPER_INFORM]: "whisper to",
 28→  [ChatType.EMOTE]: "emote",
