 36→export function formatMessage(msg: ChatMessage): string {
 37→  const message = stripColorCodes(msg.message);
 38→  const label = CHAT_TYPE_LABELS[msg.type] ?? `type ${msg.type}`;
 39→
 40→  if (msg.type === ChatType.WHISPER) {
 41→    return `[whisper from ${msg.sender}] ${message}`;
 42→  }
 43→  if (msg.type === ChatType.WHISPER_INFORM) {
 44→    return `[whisper to ${msg.sender}] ${message}`;
 45→  }
 46→  if (
 47→    msg.type === ChatType.SYSTEM &&
 48→    (msg.origin === "server" || msg.origin === "notification")
 49→  ) {
 50→    return `[server] ${message}`;
 51→  }
 52→  if (msg.type === ChatType.SYSTEM && msg.origin === "mail") {
 53→    return `[mail] ${message}`;
 54→  }
 55→  if (msg.type === ChatType.SYSTEM) {
 56→    return `[system] ${message}`;
 57→  }
 58→  if (msg.type === ChatType.ROLL) {
 59→    return `[roll] ${msg.sender} ${message}`;
 60→  }
 61→  if (msg.type === ChatType.CHANNEL && msg.channel) {
 62→    return `[${msg.channel}] ${msg.sender}: ${message}`;
 63→  }
 64→  return `[${label}] ${msg.sender}: ${message}`;
 65→}
