170→          ? "kick"
171→          : event.operation === PartyOperation.LEAVE
172→            ? "leave"
173→            : "invite";
174→      const label =
175→        event.result === PartyResult.SUCCESS
176→          ? verb === "kick"
177→            ? `Removed ${event.target} from group`
