454→    const hours = Math.floor(days * 24);
455→    return hours <= 1 ? "< 1 hr ago" : `${hours} hrs ago`;
456→  }
457→  const d = Math.floor(days);
458→  return d === 1 ? "1 day ago" : `${d} days ago`;
