461→export function formatGuildRoster(roster: GuildRoster): string {
462→  const online = roster.members.filter(
463→    (m) => m.status !== GuildMemberStatus.OFFLINE,
464→  );
465→  const offline = roster.members.filter(
466→    (m) => m.status === GuildMemberStatus.OFFLINE,
467→  );
468→  const header = roster.guildName
469→    ? `[guild] ${roster.guildName} — ${online.length}/${roster.members.length} online`
470→    : `[guild] ${online.length}/${roster.members.length} online`;
471→  const lines: string[] = [header];
472→  if (roster.motd) lines.push(`  MOTD: ${roster.motd}`);
473→  if (roster.guildInfo) lines.push(`  Info: ${roster.guildInfo}`);
474→  for (const m of online) {
