490→    guildName: roster.guildName,
491→    motd: roster.motd,
492→    guildInfo: roster.guildInfo,
493→    rankNames: roster.rankNames,
494→    count: roster.members.length,
495→    online: roster.members.filter((m) => m.status !== GuildMemberStatus.OFFLINE)
496→      .length,
497→    members: roster.members.map((m) => ({
