499→      name: m.name,
500→      rank: rankName(roster, m.rankIndex),
501→      rankIndex: m.rankIndex,
502→      level: m.level,
503→      class: CLASS_NAMES[m.playerClass] ?? `class ${m.playerClass}`,
504→      status: m.status === GuildMemberStatus.OFFLINE ? "OFFLINE" : "ONLINE",
505→      area: m.area,
506→      publicNote: m.publicNote,
507→      officerNote: m.officerNote,
508→    })),
509→  });
510→}
