522→function senderLabel(entry: MailEntry): string {
523→  if (entry.messageType === MailMessageType.AUCTION) return "Auction House";
524→  if (entry.messageType === MailMessageType.CREATURE) return "NPC";
525→  if (entry.messageType === MailMessageType.GAMEOBJECT) return "System";
526→  if (entry.messageType === MailMessageType.CALENDAR) return "Calendar";
527→  return "";
528→}
