530→export function formatMailList(
531→  entries: MailEntry[],
532→  nameCache: Map<number, string>,
533→): string {
534→  if (entries.length === 0) return "[mail] Mailbox is empty";
535→  const lines: string[] = [`=== Mailbox (${entries.length} messages) ===`];
536→  for (let i = 0; i < entries.length; i++) {
537→    const e = entries[i]!;
538→    const unread = !(e.flags & MailCheckMask.READ);
539→    const marker = unread ? "*" : " ";
540→    const idx = `#${i + 1}`;
541→    let sender = senderLabel(e);
542→    if (!sender && e.senderGuid !== undefined) {
543→      const guidLow = Number(e.senderGuid & 0xffffffffn);
544→      sender = nameCache.get(guidLow) ?? `Player`;
545→    }
546→    const subj =
547→      e.subject.length > 30 ? e.subject.slice(0, 27) + "..." : e.subject;
548→    const age = formatMailAge(e.expirationDays);
549→    lines.push(
550→      `${marker}${idx.padEnd(4)} ${sender.padEnd(15)} ${subj.padEnd(32)} ${age}`,
551→    );
552→  }
553→  return lines.join("\n");
554→}
