559→    count: entries.length,
560→    mails: entries.map((e, i) => ({
561→      index: i + 1,
562→      messageId: e.messageId,
563→      messageType: e.messageType,
564→      subject: e.subject,
565→      read: !!(e.flags & MailCheckMask.READ),
566→      expirationDays: e.expirationDays,
567→      money: e.money,
568→      itemCount: e.itemCount,
569→    })),
570→  });
571→}
