573→export function formatMailRead(entry: MailEntry, sender: string): string {
574→  const age = formatMailAge(entry.expirationDays);
575→  const lines = [
576→    `From: ${sender}`,
577→    `Subject: ${entry.subject}`,
578→    `Date: ${age} ago`,
579→  ];
580→  if (entry.money > 0) {
581→    const gold = Math.floor(entry.money / 10000);
582→    const silver = Math.floor((entry.money % 10000) / 100);
583→    const copper = entry.money % 100;
584→    const parts: string[] = [];
585→    if (gold > 0) parts.push(`${gold}g`);
586→    if (silver > 0) parts.push(`${silver}s`);
587→    if (copper > 0) parts.push(`${copper}c`);
588→    lines.push(`Money: ${parts.join(" ")}`);
589→  }
590→  if (entry.itemCount > 0) {
591→    lines.push(`Attachments: ${entry.itemCount} item(s)`);
592→  }
593→  lines.push("");
594→  lines.push(entry.body || "(no message)");
595→  return lines.join("\n");
596→}
