  96→  | { type: "guild_leader"; target: string }
  97→  | { type: "guild_motd"; message: string }
  98→  | { type: "guild_accept" }
  99→  | { type: "guild_decline" }
 100→  | { type: "mail_list" }
 101→  | { type: "mail_list_json" }
 102→  | { type: "mail_read"; index: number }
 103→  | { type: "mail_read_json"; index: number }
 104→  | { type: "mail_send"; target: string; subject: string; body: string }
 105→  | { type: "mail_delete"; index: number }
 106→  | { type: "unimplemented"; feature: string };
 107→
 108→export function parseIpcCommand(line: string): IpcCommand | undefined {
 109→  if (line.startsWith("/")) {
 110→    const parsed = parseCommand(line);
 111→    switch (parsed.type) {
 112→      case "say":
 113→      case "yell":
 114→      case "guild":
 115→      case "party":
 116→      case "emote":
 117→      case "dnd":
 118→      case "afk":
 119→        return parsed;
 120→      case "whisper":
 121→        return parsed;
 122→      case "who":
 123→        return parsed.target
 124→          ? { type: "who", filter: parsed.target }
 125→          : { type: "who" };
 126→      case "invite":
 127→      case "kick":
 128→      case "leave":
 129→      case "leader":
 130→      case "accept":
 131→      case "decline":
 132→        return parsed;
 133→      case "join-channel":
 134→        return {
 135→          type: "join_channel",
 136→          channel: parsed.channel,
 137→          password: parsed.password,
 138→        };
 139→      case "leave-channel":
 140→        return { type: "leave_channel", channel: parsed.channel };
 141→      case "friends":
 142→        return { type: "friends" };
 143→      case "add-friend":
 144→        return { type: "add_friend", target: parsed.target };
 145→      case "remove-friend":
 146→        return { type: "del_friend", target: parsed.target };
 147→      case "ignored":
 148→        return { type: "ignored" };
 149→      case "add-ignore":
 150→        return { type: "add_ignore", target: parsed.target };
 151→      case "remove-ignore":
 152→        return { type: "del_ignore", target: parsed.target };
 153→      case "roll":
 154→        return parsed;
 155→      case "guild-roster":
 156→        return { type: "guild_roster" };
 157→      case "guild-invite":
 158→        return { type: "guild_invite", target: parsed.target };
 159→      case "guild-kick":
 160→        return { type: "guild_kick", target: parsed.target };
 161→      case "guild-leave":
 162→        return { type: "guild_leave" };
 163→      case "guild-promote":
 164→        return { type: "guild_promote", target: parsed.target };
 165→      case "guild-demote":
 166→        return { type: "guild_demote", target: parsed.target };
 167→      case "guild-leader":
 168→        return { type: "guild_leader", target: parsed.target };
 169→      case "guild-motd":
 170→        return { type: "guild_motd", message: parsed.message };
 171→      case "guild-accept":
 172→        return { type: "guild_accept" };
 173→      case "guild-decline":
 174→        return { type: "guild_decline" };
 175→      case "mail-list":
 176→        return { type: "mail_list" };
 177→      case "mail-read":
 178→        return { type: "mail_read", index: parsed.index };
 179→      case "mail-send":
 180→        return {
 181→          type: "mail_send",
 182→          target: parsed.target,
 183→          subject: parsed.subject,
 184→          body: parsed.body,
 185→        };
 186→      case "mail-delete":
 187→        return { type: "mail_delete", index: parsed.index };
 188→      case "unimplemented":
 189→        return parsed;
 190→      default:
 191→        return { type: "say", message: line };
 192→    }
 193→  }
 194→
 195→  const spaceIdx = line.indexOf(" ");
 196→  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
 197→  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);
 198→
 199→  switch (verb) {
 200→    case "SAY":
 201→    case "YELL":
 202→    case "GUILD":
 203→    case "PARTY":
 204→    case "EMOTE":
 205→    case "DND":
 206→    case "AFK":
 207→      return {
 208→        type: verb.toLowerCase() as
 209→          | "say"
 210→          | "yell"
 211→          | "guild"
 212→          | "party"
 213→          | "emote"
 214→          | "dnd"
 215→          | "afk",
 216→        message: rest,
 217→      };
 218→    case "WHISPER": {
 219→      const targetEnd = rest.indexOf(" ");
 220→      if (targetEnd === -1)
 221→        return { type: "whisper", target: rest, message: "" };
 222→      return {
 223→        type: "whisper",
 224→        target: rest.slice(0, targetEnd),
 225→        message: rest.slice(targetEnd + 1),
 226→      };
 227→    }
 228→    case "READ":
 229→      return { type: "read" };
 230→    case "READ_JSON":
 231→      return { type: "read_json" };
 232→    case "READ_WAIT": {
 233→      const ms = parseInt(rest, 10);
 234→      if (!Number.isFinite(ms) || ms < 0) return undefined;
 235→      return { type: "read_wait", ms: Math.min(ms, 60_000) };
 236→    }
 237→    case "READ_WAIT_JSON": {
 238→      const ms = parseInt(rest, 10);
 239→      if (!Number.isFinite(ms) || ms < 0) return undefined;
 240→      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
 241→    }
 242→    case "STOP":
 243→      return { type: "stop" };
 244→    case "STATUS":
 245→      return { type: "status" };
 246→    case "WHO":
 247→      return rest ? { type: "who", filter: rest } : { type: "who" };
 248→    case "WHO_JSON":
 249→      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
 250→    case "INVITE":
 251→      return rest ? { type: "invite", target: rest } : undefined;
 252→    case "KICK":
 253→      return rest ? { type: "kick", target: rest } : undefined;
 254→    case "LEAVE":
 255→      if (rest) {
 256→        const channel = rest.split(" ")[0]!;
 257→        return { type: "leave_channel", channel };
 258→      }
 259→      return { type: "leave" };
 260→    case "LEADER":
 261→      return rest ? { type: "leader", target: rest } : undefined;
 262→    case "ACCEPT":
 263→      return { type: "accept" };
 264→    case "DECLINE":
 265→      return { type: "decline" };
 266→    case "NEARBY":
 267→      return { type: "nearby" };
 268→    case "NEARBY_JSON":
 269→      return { type: "nearby_json" };
 270→    case "FRIENDS":
 271→      return { type: "friends" };
 272→    case "FRIENDS_JSON":
 273→      return { type: "friends_json" };
 274→    case "ADD_FRIEND":
 275→      return rest ? { type: "add_friend", target: rest } : undefined;
 276→    case "DEL_FRIEND":
 277→      return rest ? { type: "del_friend", target: rest } : undefined;
 278→    case "IGNORED":
 279→      return { type: "ignored" };
 280→    case "IGNORED_JSON":
 281→      return { type: "ignored_json" };
 282→    case "ADD_IGNORE":
 283→      return rest ? { type: "add_ignore", target: rest } : undefined;
 284→    case "DEL_IGNORE":
 285→      return rest ? { type: "del_ignore", target: rest } : undefined;
 286→    case "JOIN": {
 287→      if (!rest) return undefined;
 288→      const [channel, password] = rest.split(" ") as [string, string?];
 289→      return { type: "join_channel", channel, password };
 290→    }
 291→    case "GUILD_ROSTER":
 292→      return { type: "guild_roster" };
 293→    case "GUILD_ROSTER_JSON":
 294→      return { type: "guild_roster_json" };
 295→    case "GINVITE":
 296→      return rest ? { type: "guild_invite", target: rest } : undefined;
 297→    case "GKICK":
 298→      return rest ? { type: "guild_kick", target: rest } : undefined;
 299→    case "GLEAVE":
 300→      return { type: "guild_leave" };
 301→    case "GPROMOTE":
 302→      return rest ? { type: "guild_promote", target: rest } : undefined;
 303→    case "GDEMOTE":
 304→      return rest ? { type: "guild_demote", target: rest } : undefined;
 305→    case "GLEADER":
 306→      return rest ? { type: "guild_leader", target: rest } : undefined;
 307→    case "GMOTD":
 308→      return { type: "guild_motd", message: rest };
 309→    case "GACCEPT":
 310→      return { type: "guild_accept" };
 311→    case "GDECLINE":
 312→      return { type: "guild_decline" };
 313→    case "MAIL":
 314→      return { type: "mail_list" };
 315→    case "MAIL_JSON":
 316→      return { type: "mail_list_json" };
 317→    case "MAIL_READ": {
 318→      const n = parseInt(rest, 10);
 319→      return Number.isFinite(n) && n > 0
 320→        ? { type: "mail_read", index: n }
 321→        : undefined;
 322→    }
 323→    case "MAIL_READ_JSON": {
 324→      const n = parseInt(rest, 10);
 325→      return Number.isFinite(n) && n > 0
 326→        ? { type: "mail_read_json", index: n }
 327→        : undefined;
 328→    }
 329→    case "MAIL_SEND": {
 330→      const parsed = parseCommand(`/mail send ${rest}`);
 331→      if (parsed.type === "mail-send") {
 332→        return {
 333→          type: "mail_send",
 334→          target: parsed.target,
 335→          subject: parsed.subject,
 336→          body: parsed.body,
 337→        };
 338→      }
 339→      return undefined;
 340→    }
 341→    case "MAIL_DELETE": {
 342→      const n = parseInt(rest, 10);
 343→      return Number.isFinite(n) && n > 0
 344→        ? { type: "mail_delete", index: n }
 345→        : undefined;
 346→    }
 347→    case "ROLL": {
 348→      const parts = rest.split(" ").filter(Boolean);
 349→      if (parts.length >= 2)
 350→        return {
 351→          type: "roll",
 352→          min: parseInt(parts[0]!, 10),
 353→          max: parseInt(parts[1]!, 10),
 354→        };
 355→      if (parts.length === 1)
 356→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
 357→      return { type: "roll", min: 1, max: 100 };
 358→    }
 359→    default:
 360→      return line ? { type: "chat", message: line } : undefined;
 361→  }
 362→}
 363→
 364→export function writeLines(socket: IpcSocket, lines: string[]): void {
 365→  for (const line of lines) socket.write(line + "\n");
 366→  socket.write("\n");
 367→}
 368→
 369→function drainText(events: RingBuffer<EventEntry>): string[] {
 370→  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
 371→}
 372→
 373→function drainJson(events: RingBuffer<EventEntry>): string[] {
 374→  return events.drain().map((e) => e.json);
 375→}
 376→
 377→function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
 378→  return events
 379→    .slice(from)
 380→    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
 381→}
 382→
 383→function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
 384→  return events.slice(from).map((e) => e.json);
 385→}
 386→
 387→export async function dispatchCommand(
 388→  cmd: IpcCommand,
 389→  handle: WorldHandle,
 390→  events: RingBuffer<EventEntry>,
 391→  socket: IpcSocket,
 392→  cleanup: () => void,
 393→): Promise<boolean> {
 394→  switch (cmd.type) {
 395→    case "chat": {
 396→      handle.sendInCurrentMode(cmd.message);
 397→      const mode = handle.getLastChatMode();
 398→      const label =
 399→        mode.type === "whisper"
 400→          ? `WHISPER ${mode.target}`
 401→          : mode.type === "channel"
 402→            ? `CHANNEL ${mode.channel}`
 403→            : mode.type.toUpperCase();
 404→      writeLines(socket, [`OK ${label}`]);
 405→      return false;
 406→    }
 407→    case "say":
 408→      handle.sendSay(cmd.message);
 409→      writeLines(socket, ["OK"]);
 410→      return false;
 411→    case "yell":
 412→      handle.sendYell(cmd.message);
 413→      writeLines(socket, ["OK"]);
 414→      return false;
 415→    case "guild":
 416→      handle.sendGuild(cmd.message);
 417→      writeLines(socket, ["OK"]);
 418→      return false;
 419→    case "party":
 420→      handle.sendParty(cmd.message);
 421→      writeLines(socket, ["OK"]);
 422→      return false;
 423→    case "emote":
 424→      handle.sendEmote(cmd.message);
 425→      writeLines(socket, ["OK"]);
 426→      return false;
 427→    case "dnd":
 428→      handle.sendDnd(cmd.message);
 429→      writeLines(socket, ["OK"]);
 430→      return false;
 431→    case "afk":
 432→      handle.sendAfk(cmd.message);
 433→      writeLines(socket, ["OK"]);
 434→      return false;
 435→    case "whisper":
 436→      handle.sendWhisper(cmd.target, cmd.message);
 437→      writeLines(socket, ["OK"]);
 438→      return false;
 439→    case "roll":
 440→      handle.sendRoll(cmd.min, cmd.max);
 441→      writeLines(socket, ["OK"]);
 442→      return false;
 443→    case "read":
 444→      writeLines(socket, drainText(events));
 445→      return false;
 446→    case "read_json":
 447→      writeLines(socket, drainJson(events));
 448→      return false;
 449→    case "read_wait": {
 450→      const start = events.writePos;
 451→      await new Promise<void>((resolve) => {
 452→        setTimeout(() => {
 453→          writeLines(socket, sliceText(events, start));
 454→          resolve();
 455→        }, cmd.ms);
 456→      });
 457→      return false;
 458→    }
 459→    case "read_wait_json": {
 460→      const start = events.writePos;
 461→      await new Promise<void>((resolve) => {
 462→        setTimeout(() => {
 463→          writeLines(socket, sliceJson(events, start));
 464→          resolve();
 465→        }, cmd.ms);
 466→      });
 467→      return false;
 468→    }
 469→    case "stop":
 470→      writeLines(socket, ["OK"]);
 471→      cleanup();
 472→      return true;
 473→    case "status":
 474→      writeLines(socket, ["CONNECTED"]);
 475→      return false;
 476→    case "who": {
 477→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
 478→      writeLines(socket, formatWhoResults(results).split("\n"));
 479→      return false;
 480→    }
 481→    case "who_json": {
 482→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
 483→      writeLines(socket, [formatWhoResultsJson(results)]);
 484→      return false;
 485→    }
 486→    case "invite":
 487→      handle.invite(cmd.target);
 488→      writeLines(socket, ["OK"]);
 489→      return false;
 490→    case "kick":
 491→      handle.uninvite(cmd.target);
 492→      writeLines(socket, ["OK"]);
 493→      return false;
 494→    case "leave":
 495→      handle.leaveGroup();
 496→      writeLines(socket, ["OK"]);
 497→      return false;
 498→    case "leader":
 499→      handle.setLeader(cmd.target);
 500→      writeLines(socket, ["OK"]);
 501→      return false;
 502→    case "accept":
 503→      handle.acceptInvite();
 504→      writeLines(socket, ["OK"]);
 505→      return false;
 506→    case "decline":
 507→      handle.declineInvite();
 508→      writeLines(socket, ["OK"]);
 509→      return false;
 510→    case "nearby": {
 511→      const entities = handle.getNearbyEntities();
 512→      writeLines(socket, entities.map(formatNearbyLine));
 513→      return false;
 514→    }
 515→    case "nearby_json": {
 516→      const entities = handle.getNearbyEntities();
 517→      writeLines(
 518→        socket,
 519→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
 520→      );
 521→      return false;
 522→    }
 523→    case "friends": {
 524→      const friends = handle.getFriends();
 525→      writeLines(socket, formatFriendList(friends).split("\n"));
 526→      return false;
 527→    }
 528→    case "friends_json": {
 529→      const friends = handle.getFriends();
 530→      writeLines(socket, [formatFriendListJson(friends)]);
 531→      return false;
 532→    }
 533→    case "add_friend":
 534→      handle.addFriend(cmd.target);
 535→      writeLines(socket, ["OK"]);
 536→      return false;
 537→    case "del_friend":
 538→      handle.removeFriend(cmd.target);
 539→      writeLines(socket, ["OK"]);
 540→      return false;
 541→    case "ignored": {
 542→      const ignored = handle.getIgnored();
 543→      writeLines(socket, formatIgnoreList(ignored).split("\n"));
 544→      return false;
 545→    }
 546→    case "ignored_json": {
 547→      const ignored = handle.getIgnored();
 548→      writeLines(socket, [formatIgnoreListJson(ignored)]);
 549→      return false;
 550→    }
 551→    case "add_ignore":
 552→      handle.addIgnore(cmd.target);
 553→      writeLines(socket, ["OK"]);
 554→      return false;
 555→    case "del_ignore":
 556→      handle.removeIgnore(cmd.target);
 557→      writeLines(socket, ["OK"]);
 558→      return false;
 559→    case "join_channel":
 560→      handle.joinChannel(cmd.channel, cmd.password);
 561→      writeLines(socket, ["OK"]);
 562→      return false;
 563→    case "leave_channel":
 564→      handle.leaveChannel(cmd.channel);
 565→      writeLines(socket, ["OK"]);
 566→      return false;
 567→    case "guild_roster": {
 568→      const roster = await handle.requestGuildRoster();
 569→      if (roster) {
 570→        writeLines(socket, formatGuildRoster(roster).split("\n"));
 571→      } else {
 572→        writeLines(socket, ["[guild] No guild roster available"]);
 573→      }
 574→      return false;
 575→    }
 576→    case "guild_roster_json": {
 577→      const roster = await handle.requestGuildRoster();
 578→      if (roster) {
 579→        writeLines(socket, [formatGuildRosterJson(roster)]);
 580→      } else {
 581→        writeLines(socket, [
 582→          JSON.stringify({ type: "GUILD_ROSTER", members: [] }),
 583→        ]);
 584→      }
 585→      return false;
 586→    }
 587→    case "guild_invite":
 588→      handle.guildInvite(cmd.target);
 589→      writeLines(socket, ["OK"]);
 590→      return false;
 591→    case "guild_kick":
 592→      handle.guildRemove(cmd.target);
 593→      writeLines(socket, ["OK"]);
 594→      return false;
 595→    case "guild_leave":
 596→      handle.guildLeave();
 597→      writeLines(socket, ["OK"]);
 598→      return false;
 599→    case "guild_promote":
 600→      handle.guildPromote(cmd.target);
 601→      writeLines(socket, ["OK"]);
 602→      return false;
 603→    case "guild_demote":
 604→      handle.guildDemote(cmd.target);
 605→      writeLines(socket, ["OK"]);
 606→      return false;
 607→    case "guild_leader":
 608→      handle.guildLeader(cmd.target);
 609→      writeLines(socket, ["OK"]);
 610→      return false;
 611→    case "guild_motd":
 612→      handle.guildMotd(cmd.message);
 613→      writeLines(socket, ["OK"]);
 614→      return false;
 615→    case "guild_accept":
 616→      handle.acceptGuildInvite();
 617→      writeLines(socket, ["OK"]);
 618→      return false;
 619→    case "guild_decline":
 620→      handle.declineGuildInvite();
 621→      writeLines(socket, ["OK"]);
 622→      return false;
 623→    case "mail_list": {
 624→      if (!handle.getMailboxGuid()) {
 625→        writeLines(socket, ["ERR No mailbox open"]);
 626→        return false;
 627→      }
 628→      const entries = await handle.requestMailList();
 629→      writeLines(
 630→        socket,
 631→        formatMailList(entries, handle.getNameCache()).split("\n"),
 632→      );
 633→      return false;
 634→    }
 635→    case "mail_list_json": {
 636→      if (!handle.getMailboxGuid()) {
 637→        writeLines(socket, [
 638→          JSON.stringify({ type: "MAIL_LIST", error: "No mailbox open" }),
 639→        ]);
 640→        return false;
 641→      }
 642→      const entries = await handle.requestMailList();
 643→      writeLines(socket, [formatMailListJson(entries)]);
 644→      return false;
 645→    }
 646→    case "mail_read": {
 647→      if (!handle.getMailboxGuid()) {
 648→        writeLines(socket, ["ERR No mailbox open"]);
 649→        return false;
 650→      }
 651→      const cache = handle.getMailCache();
 652→      const entry = cache[cmd.index - 1];
 653→      if (!entry) {
 654→        writeLines(socket, [`ERR No mail #${cmd.index}`]);
 655→        return false;
 656→      }
 657→      let sender = "Unknown";
 658→      if (entry.senderGuid !== undefined) {
 659→        const guidLow = Number(entry.senderGuid & 0xffffffffn);
 660→        sender = handle.getNameCache().get(guidLow) ?? "Unknown";
 661→      }
 662→      handle.markMailAsRead(entry.messageId);
 663→      writeLines(socket, formatMailRead(entry, sender).split("\n"));
 664→      return false;
 665→    }
 666→    case "mail_read_json": {
 667→      if (!handle.getMailboxGuid()) {
 668→        writeLines(socket, [
 669→          JSON.stringify({ type: "MAIL_READ", error: "No mailbox open" }),
 670→        ]);
 671→        return false;
 672→      }
 673→      const cache = handle.getMailCache();
 674→      const entry = cache[cmd.index - 1];
 675→      if (!entry) {
 676→        writeLines(socket, [
 677→          JSON.stringify({ type: "MAIL_READ", error: `No mail #${cmd.index}` }),
 678→        ]);
 679→        return false;
 680→      }
 681→      let sender = "Unknown";
 682→      if (entry.senderGuid !== undefined) {
 683→        const guidLow = Number(entry.senderGuid & 0xffffffffn);
 684→        sender = handle.getNameCache().get(guidLow) ?? "Unknown";
 685→      }
 686→      handle.markMailAsRead(entry.messageId);
 687→      writeLines(socket, [formatMailReadJson(entry, sender)]);
 688→      return false;
 689→    }
 690→    case "mail_send": {
 691→      if (!handle.getMailboxGuid()) {
 692→        writeLines(socket, ["ERR No mailbox open"]);
 693→        return false;
 694→      }
 695→      handle.sendMail(cmd.target, cmd.subject, cmd.body);
 696→      writeLines(socket, ["OK"]);
 697→      return false;
 698→    }
 699→    case "mail_delete": {
 700→      if (!handle.getMailboxGuid()) {
 701→        writeLines(socket, ["ERR No mailbox open"]);
 702→        return false;
 703→      }
 704→      const delCache = handle.getMailCache();
 705→      const delEntry = delCache[cmd.index - 1];
 706→      if (!delEntry) {
 707→        writeLines(socket, [`ERR No mail #${cmd.index}`]);
 708→        return false;
 709→      }
 710→      handle.deleteMail(delEntry.messageId);
 711→      writeLines(socket, ["OK"]);
 712→      return false;
 713→    }
 714→    case "unimplemented":
 715→      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
 716→      return false;
 717→  }
 718→}
