 720→function objectTypeName(type: ObjectType): string {
 721→  switch (type) {
 722→    case ObjectType.UNIT:
 723→      return "NPC";
 724→    case ObjectType.PLAYER:
 725→      return "Player";
 726→    default:
 727→      return `type ${type}`;
 728→  }
 729→}
 730→
 731→function formatNearbyLine(entity: Entity): string {
 732→  if (
 733→    entity.objectType === ObjectType.UNIT ||
 734→    entity.objectType === ObjectType.PLAYER
 735→  ) {
 736→    const unit = entity as UnitEntity;
 737→    const name = entity.name ?? "Unknown";
 738→    const kind = objectTypeName(entity.objectType);
 739→    const level = unit.level > 0 ? `, level ${unit.level}` : "";
 740→    const hp = `HP ${unit.health}/${unit.maxHealth}`;
 741→    const pos = entity.position
 742→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
 743→      : "";
 744→    return `${name} (${kind}${level}) ${hp}${pos}`;
 745→  }
 746→  if (entity.objectType === ObjectType.GAMEOBJECT) {
 747→    const name = entity.name ?? "Unknown";
 748→    const pos = entity.position
 749→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
 750→      : "";
 751→    return `${name} (GameObject)${pos}`;
 752→  }
 753→  return `Entity 0x${entity.guid.toString(16)} (${objectTypeName(entity.objectType)})`;
 754→}
 755→
 756→function objectTypeString(type: ObjectType): string {
 757→  switch (type) {
 758→    case ObjectType.UNIT:
 759→      return "unit";
 760→    case ObjectType.PLAYER:
 761→      return "player";
 762→    case ObjectType.GAMEOBJECT:
 763→      return "gameobject";
 764→    default:
 765→      return "object";
 766→  }
 767→}
