 769→function formatNearbyObj(entity: Entity): Record<string, unknown> {
 770→  const obj: Record<string, unknown> = {
 771→    guid: `0x${entity.guid.toString(16)}`,
 772→    type: objectTypeString(entity.objectType),
 773→    name: entity.name,
 774→  };
 775→  if (
 776→    entity.objectType === ObjectType.UNIT ||
 777→    entity.objectType === ObjectType.PLAYER
 778→  ) {
 779→    const unit = entity as UnitEntity;
 780→    obj["level"] = unit.level;
 781→    obj["health"] = unit.health;
 782→    obj["maxHealth"] = unit.maxHealth;
 783→  }
 784→  if (entity.objectType === ObjectType.GAMEOBJECT) {
 785→    obj["gameObjectType"] = (entity as GameObjectEntity).gameObjectType;
 786→  }
 787→  if (entity.position) {
 788→    obj["x"] = entity.position.x;
 789→    obj["y"] = entity.position.y;
 790→    obj["z"] = entity.position.z;
 791→  }
 792→  return obj;
 793→}
