 795→function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
 796→  switch (event.type) {
 797→    case "invite_received":
 798→      return { type: "GROUP_INVITE", from: event.from };
 799→    case "command_result":
 800→      return {
 801→        type: "GROUP_COMMAND_RESULT",
 802→        operation: event.operation,
 803→        target: event.target,
 804→        result: event.result,
 805→      };
 806→    case "leader_changed":
