 895→function formatGuildEvent(event: GuildEvent): string {
 896→  switch (event.type) {
 897→    case "guild-roster":
 898→      return `[guild] Roster updated: ${event.roster.members.length} members`;
 899→    case "promotion":
 900→      return `[guild] ${event.officer} promoted ${event.member} to ${event.rank}`;
 901→    case "demotion":
 902→      return `[guild] ${event.officer} demoted ${event.member} to ${event.rank}`;
 903→    case "motd":
