 905→    case "joined":
 906→      return `[guild] ${event.name} has joined the guild`;
 907→    case "left":
 908→      return `[guild] ${event.name} has left the guild`;
 909→    case "removed":
 910→      return `[guild] ${event.officer} removed ${event.member} from the guild`;
 911→    case "leader_is":
 912→      return `[guild] ${event.name} is the guild leader`;
 913→    case "leader_changed":
 914→      return `[guild] ${event.oldLeader} has made ${event.newLeader} the new guild leader`;
 915→    case "disbanded":
 916→      return "[guild] Guild has been disbanded";
 917→    case "signed_on":
 918→      return `[guild] ${event.name} has come online`;
 919→    case "signed_off":
 920→      return `[guild] ${event.name} has gone offline`;
 921→    case "command_result":
 922→      return formatGuildCommandError(event.command, event.name, event.result)!;
 923→    case "guild_invite":
